INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-cut-style', 'Signature Cut & Style', 'signature-cut-and-style', 'Hair', 'A consultative haircut tailored to your hair texture, lifestyle, and the way you actually wear your hair day to day. Finished with a blow-dry shaped to your face.', 75, 12000, 2400, 'https://images.unsplash.com/photo-1560869713-da86bd4f31ba?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-single-process', 'Single-Process Color', 'single-process-color', 'Hair', 'All-over color for grey coverage, depth, or a tonal refresh. We mix a custom formula at the bowl and process under low heat for an even, lived-in finish.', 105, 14500, 2900, 'https://images.unsplash.com/photo-1522337360788-8b13dee7a37e?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-highlights-balayage', 'Highlights / Balayage', 'highlights-balayage', 'Hair', 'Hand-painted dimension built around your natural growth pattern. We work in soft, blended panels so regrowth never looks like a hard line.', 180, 24000, 4800, 'https://images.unsplash.com/photo-1605497788044-5a32c7078486?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-glaze-gloss', 'Glaze & Gloss Treatment', 'glaze-and-gloss-treatment', 'Hair', 'An acidic clear or tinted gloss that seals the cuticle, deepens shine, and refreshes faded tone. Pairs naturally with a cut between color visits.', 45, 6500, 1300, 'https://images.unsplash.com/photo-1519415943484-9fa1873496d4?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-bridal-hair', 'Bridal Hair', 'bridal-hair', 'Hair', 'On-site or in-salon bridal styling, built from a preview session two to four weeks before the wedding. We plan around your dress neckline, veil placement, and how long the day actually runs.', 120, 28500, 5700, 'https://images.unsplash.com/photo-1595956553066-fe24a8c33395?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-aura-manicure', 'Aura Manicure', 'aura-manicure', 'Nails', 'A clean, dry-prep manicure: gentle cuticle work, hand massage with warm balm, and your choice of polish from our non-toxic line.', 45, 4800, 960, 'https://images.unsplash.com/photo-1604654894610-df63bc536371?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-aura-pedicure', 'Aura Pedicure', 'aura-pedicure', 'Nails', 'A grounded pedicure in our heated stone chairs. Soak, exfoliation up to the knee, callus work, and a long lower-leg massage before polish.', 60, 7200, 1440, 'https://images.unsplash.com/photo-1519014816548-bf5fe059798b?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-gel-manicure', 'Gel Manicure', 'gel-manicure', 'Nails', 'Long-wear gel with the same careful nail prep as our classic manicure. Soak-off included if you''re coming in with existing gel.', 60, 6200, 1240, 'https://images.unsplash.com/photo-1607779097040-26e80aa78e66?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-aura-facial', 'The Aura Facial', 'the-aura-facial', 'Skin', 'Our signature facial. Double cleanse, custom enzyme exfoliation, extractions if you want them, LED, and a finishing massage with cold globes.', 75, 16500, 3300, 'https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-microcurrent-lift', 'Microcurrent Lift', 'microcurrent-lift', 'Skin', 'Low-level electrical currents that re-educate the facial muscles. Best in a series of six, but you''ll see a visible lift after the first session.', 60, 19500, 3900, 'https://images.unsplash.com/photo-1596178065887-1198b6148b2b?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-dermaplane-glow', 'Dermaplane & Glow', 'dermaplane-and-glow', 'Skin', 'Manual exfoliation with a surgical blade to remove dead surface cells and peach fuzz, followed by a brightening mask and SPF. Makeup sits like glass after.', 50, 13500, 2700, 'https://images.unsplash.com/photo-1616394584738-fc6e612e71b9?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-massage-60', '60-Minute Massage', 'massage-60', 'Spa', 'Customized pressure from light Swedish to focused deep tissue. Tell your therapist what''s tight; the hour shapes around it.', 60, 13000, 2600, 'https://images.unsplash.com/photo-1600334129128-685c5582fd35?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-massage-90', '90-Minute Massage', 'massage-90', 'Spa', 'The extra thirty minutes let your therapist work slowly through neck, shoulders, hips, and feet without rushing. Our most-requested spa appointment.', 90, 18500, 3700, 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.services (id, name, slug, category, description, duration_minutes, price_cents, deposit_cents, image_url) VALUES ('svc-body-polish-wrap', 'Body Polish + Hydration Wrap', 'body-polish-and-wrap', 'Spa', 'Full-body sugar polish followed by a shea and oat hydration wrap. You rest under heated linens while we massage scalp and feet.', 90, 17500, 3500, 'https://images.unsplash.com/photo-1591343395082-e120087004b4?w=1200&q=80') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-elena', 'Elena Vasquez', 'elena-vasquez', 'Founder & Creative Director', 'Elena opened Aura after fifteen years between Madrid and New York, including six on the color floor at a Bumble and bumble flagship. She teaches an annual hand-painting workshop for early-career colorists and still takes her own clients three days a week.', 'https://images.unsplash.com/photo-1580489944761-15a19d654956?w=600&q=80', ARRAY['Balayage', 'Lived-in color', 'Editorial cuts']) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-marcus', 'Marcus Okafor', 'marcus-okafor', 'Master Stylist', 'Marcus trained in London under a Vidal Sassoon-lineage cutter before moving stateside in 2019. His chair runs heavy with curly clients who want a real shape, not just a wash-and-go. He keeps a small bridal book each summer.', 'https://images.unsplash.com/photo-1531123897727-8f129e1688ce?w=600&q=80', ARRAY['Curly & coily hair', 'Sharp cuts', 'Bridal styling']) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-priya', 'Priya Shah', 'priya-shah', 'Senior Colorist', 'Priya is the colorist clients send their friends to when something has gone wrong elsewhere. She''s especially careful with dark hair that''s been over-lightened, and she keeps a strict consult policy: nothing happens at the bowl until the plan is on paper.', 'https://images.unsplash.com/photo-1573496359142-b8d87734a5a2?w=600&q=80', ARRAY['Brunette dimension', 'Grey-blending', 'Color correction']) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-naomi', 'Naomi Tanaka', 'naomi-tanaka', 'Lead Skincare Therapist', 'Naomi is a licensed esthetician with advanced training in microcurrent and chemical peels. She came to Aura from a dermatology practice in San Francisco, where she worked alongside the resident MDs on post-procedure recovery facials.', 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?w=600&q=80', ARRAY['Microcurrent', 'Acne protocols', 'Pre-event skin prep']) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-theo', 'Theo Laurent', 'theo-laurent', 'Senior Massage Therapist', 'Theo holds a 1000-hour California license plus continuing certifications in pre-natal and sports massage. He works with several local runners and dancers, and his deep-tissue clients tend to book him on a standing six-week rotation.', 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=600&q=80', ARRAY['Deep tissue', 'Pre/post-natal', 'Sports recovery']) ON CONFLICT (id) DO NOTHING;
INSERT INTO public.stylists (id, name, slug, title, bio, avatar_url, specialties) VALUES ('sty-jules', 'Jules Moreau', 'jules-moreau', 'Nail Specialist', 'Jules came up through a Paris nail studio that specialized in editorial work and brought that obsessive prep standard with them. Expect a careful dry cuticle, a clean apex, and gel that lasts the full three weeks.', 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?w=600&q=80', ARRAY['Gel', 'Structured manicures', 'Nail art']) ON CONFLICT (id) DO NOTHING;
